const ctx = $input.first().json;
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://YOUR_SUPABASE_REF.supabase.co/rest/v1';
const hdr = { apikey };

const [roster, aliases] = await Promise.all([
  this.helpers.httpRequest({ method: 'GET', url: base + '/agents?select=name,tier,site,crm_agent_id,email&is_active=eq.true', headers: hdr, json: true }),
  this.helpers.httpRequest({ method: 'GET', url: base + '/agent_name_aliases?select=canonical_name,crm_name', headers: hdr, json: true })
]);

if (!roster || roster.length === 0) {
  return [{ json: { error: true, message: 'No active agents found in Supabase', ...ctx } }];
}

const nameAliases = {};
for (const a of (aliases || [])) nameAliases[a.canonical_name] = a.crm_name;

const targetAgents = roster.map((a) => a.name);
const agentTiers = {};
const agentSites = {};
const agentCrmIds = {};
const agentEmails = {};
for (const a of roster) {
  agentTiers[a.name] = a.tier;
  agentSites[a.name] = a.site || 'RMT';
  if (a.crm_agent_id) agentCrmIds[a.name] = a.crm_agent_id;
  if (a.email) agentEmails[a.name] = a.email;
}

return [{
  json: {
    ...ctx,
    targetAgents,
    agentTiers,
    agentSites,
    agentCrmIds,
    agentEmails,
    nameAliases,
    agentCount: roster.length,
    apifyBody: JSON.stringify({
      crmUsername: 'YOUR_CRM_USERNAME',
      crmPassword: 'YOUR_CRM_PASSWORD',
      targetAgents,
      agentTiers,
      agentCrmIds,
      nameAliases,
      requestDelay: 1500
    })
  }
}];

const runStatus = $input.first().json;
const datasetId = runStatus?.data?.defaultDatasetId;
const runId = runStatus?.data?.id || 'unknown';
if (!datasetId) {
  return [{ json: { error: true, message: 'No defaultDatasetId. runId=' + runId } }];
}
const token = 'YOUR_APIFY_API_TOKEN';
async function fetchDataset(dsId, attempt) {
  const url = `https://api.apify.com/v2/datasets/${dsId}/items?token=${token}`;
  const raw = await this.helpers.httpRequest({ method: 'GET', url, encoding: 'utf-8', returnFullResponse: false, timeout: 60000, headers: { Accept: 'application/json' } });
  let parsed = raw;
  if (typeof raw === 'string') {
    try { parsed = JSON.parse(raw); } catch (e) { throw new Error('JSON parse failed (attempt ' + attempt + '): ' + raw.substring(0, 200)); }
  }
  return parsed;
}
let items, lastErr;
for (let attempt = 1; attempt <= 3; attempt++) {
  try { items = await fetchDataset.call(this, datasetId, attempt); if (Array.isArray(items) && items.length > 0) break; if (attempt < 3) await new Promise((r) => setTimeout(r, 10000)); }
  catch (err) { lastErr = err; if (attempt < 3) await new Promise((r) => setTimeout(r, 10000)); }
}
if (!items || !Array.isArray(items) || items.length === 0) {
  if (items && typeof items === 'object' && !Array.isArray(items)) items = [items];
  else return [{ json: { error: true, message: 'Dataset empty after 3 attempts. ' + (lastErr?.message || ''), datasetId, runId } }];
}
const pipelineItem = items.find((i) => i._type === 'pipeline_compliance');
if (!pipelineItem) return [{ json: { error: true, message: 'No pipeline_compliance item in dataset', datasetId, runId } }];
let sd = pipelineItem.scrape_date;
if (sd) {
  const [sy, sm, sdd] = sd.split('-').map(Number);
  const sdt = new Date(sy, sm - 1, sdd);
  const dow = sdt.getDay();
  if (dow === 0) sdt.setDate(sdt.getDate() - 2);
  else if (dow === 6) sdt.setDate(sdt.getDate() - 1);
  sd = sdt.toISOString().slice(0, 10);
}
const ctx = $node['Fetch Agent Roster'].json;
return [{ json: {
  scrape_date: sd,
  agents: pipelineItem.agents || [],
  summary: pipelineItem.summary || {},
  agentSites: ctx.agentSites || {},
  agentEmails: ctx.agentEmails || {},
  snapshot_label: ctx.snapshot_label,
  label_pretty: ctx.label_pretty,
  is_eod: ctx.is_eod
}}];

// MORNING — state of pipeline (Past Dues + Untouched = Actionable)
const payload = $node['Fetch Dataset & Parse'].json;
const agents = payload.agents || [];
const date = payload.scrape_date;
const fmt = (n) => '$' + Math.round(n).toLocaleString();

// DB columns total_stale / revenue_at_risk now physically hold:
//   total_stale     = past_due + new_leads (Actionable Leads)
//   revenue_at_risk = Actionable × avg premium (Premium @ Stake)
const totalPastDue   = agents.reduce((s, a) => s + (a.past_due_follow_ups || 0), 0);
const totalUntouched = agents.reduce((s, a) => s + (a.new_leads || 0), 0);
const totalQueue     = agents.reduce((s, a) => s + (a.call_queue_count || 0), 0);
const totalFU        = agents.reduce((s, a) => s + (a.todays_follow_ups || 0), 0);
const totalActionable= agents.reduce((s, a) => s + (a.total_stale || 0), 0);
const totalStake     = agents.reduce((s, a) => s + (a.revenue_at_risk || 0), 0);
const overCap = agents.filter((a) => (a.total_stale || 0) > 30);
const critical = agents.filter((a) => (a.past_due_follow_ups || 0) > 3 || (a.total_stale || 0) > 40);
const clean = agents.filter((a) => (a.past_due_follow_ups || 0) === 0 && (a.total_stale || 0) <= 20);

const sortedCrit = [...critical].sort((a, b) => (b.past_due_follow_ups || 0) - (a.past_due_follow_ups || 0) || (b.total_stale || 0) - (a.total_stale || 0));

function line(a) {
  const pd = a.past_due_follow_ups || 0;
  const ut = a.new_leads || 0;
  const act = a.total_stale || 0;
  const fu = a.todays_follow_ups || 0;
  const stake = a.revenue_at_risk || 0;
  return `*${a.agent_name}* — ${act} actionable (${pd} past due + ${ut} untouched) · ${fu} F/U today · ${fmt(stake)} @ stake`;
}

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: ':sunrise: Morning Pipeline State — ' + date, emoji: true } },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: '*Agents*\n' + agents.length },
    { type: 'mrkdwn', text: '*Past Due (org)*\n' + totalPastDue },
    { type: 'mrkdwn', text: '*Untouched*\n' + totalUntouched },
    { type: 'mrkdwn', text: '*Today F/U*\n' + totalFU }
  ]},
  { type: 'section', text: { type: 'mrkdwn', text: `*${critical.length}* critical · *${overCap.length}* over capacity (>30 actionable) · *${clean.length}* clean · *${totalActionable}* total actionable · ${fmt(totalStake)} premium @ stake` } },
  { type: 'divider' }
];

if (sortedCrit.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:rotating_light: Critical (work first)*' } });
  for (let i = 0; i < Math.min(sortedCrit.length, 10); i++) blocks.push({ type: 'section', text: { type: 'mrkdwn', text: line(sortedCrit[i]) } });
  if (sortedCrit.length > 10) blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: '…and ' + (sortedCrit.length - 10) + ' more critical.' }] });
  blocks.push({ type: 'divider' });
}

const overCapClean = overCap.filter((a) => !critical.includes(a));
if (overCapClean.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:warning: Over capacity — clear backlog before new activity*\n' + overCapClean.slice(0, 12).map((a) => `${a.agent_name} (${a.total_stale} actionable)`).join(', ') } });
  blocks.push({ type: 'divider' });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Rule: clear past dues before any new inbound. Midday recap at 1pm CST.' }] });

return [{ json: { text: 'Morning pipeline — ' + date + ': ' + critical.length + ' critical, ' + clean.length + ' clean', blocks } }];

// MIDDAY — deltas vs morning snapshot for the same date
const payload = $node['Fetch Dataset & Parse'].json;
const agents = payload.agents || [];
const date = payload.scrape_date;
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://YOUR_SUPABASE_REF.supabase.co/rest/v1';

let morning = [];
try {
  morning = await this.helpers.httpRequest({
    method: 'GET',
    url: base + '/pipeline_compliance_intraday?select=agent_name,past_due_follow_ups,new_leads,call_queue_count,total_stale,revenue_at_risk&scrape_date=eq.' + date + '&snapshot_label=eq.morning',
    headers: { apikey },
    json: true
  }) || [];
} catch (e) { morning = []; }
const morningMap = new Map(morning.map((m) => [m.agent_name, m]));

const fmt = (n) => '$' + Math.round(n).toLocaleString();
const signed = (n) => (n > 0 ? '+' : '') + n;

// total_stale column physically stores Actionable Leads (past_due + new_leads).
// revenue_at_risk column physically stores Premium @ Stake.
const withDeltas = agents.map((a) => {
  const m = morningMap.get(a.agent_name) || {};
  return {
    ...a,
    delta_past_due:   (a.past_due_follow_ups || 0) - (m.past_due_follow_ups || 0),
    delta_actionable: (a.total_stale || 0)         - (m.total_stale || 0),
    delta_queue:      (a.call_queue_count || 0)    - (m.call_queue_count || 0),
    delta_stake:      (a.revenue_at_risk || 0)     - (m.revenue_at_risk || 0)
  };
});

const movers = withDeltas.filter((a) => a.delta_past_due < 0 || a.delta_actionable < -2).sort((a, b) => (a.delta_past_due + a.delta_actionable) - (b.delta_past_due + b.delta_actionable));
const stuck = withDeltas.filter((a) => a.delta_past_due > 0 || a.delta_actionable > 2).sort((a, b) => (b.delta_past_due + b.delta_actionable) - (a.delta_past_due + a.delta_actionable));
const nowCritical = withDeltas.filter((a) => (a.past_due_follow_ups || 0) > 3 || (a.total_stale || 0) > 40);

const totalStake = agents.reduce((s, a) => s + (a.revenue_at_risk || 0), 0);
const totalStakeMorning = (morning || []).reduce((s, m) => s + (m.revenue_at_risk || 0), 0);
const stakeDelta = totalStake - totalStakeMorning;

function movLine(a) {
  return `*${a.agent_name}* — past due ${signed(a.delta_past_due)}, actionable ${signed(a.delta_actionable)}, premium @ stake ${signed(Math.round(a.delta_stake))}`;
}

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: ':bar_chart: Midday Movement — ' + date, emoji: true } },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: '*Org Premium @ Stake*\n' + fmt(totalStake) },
    { type: 'mrkdwn', text: '*Δ vs AM*\n' + (stakeDelta >= 0 ? '+' : '') + fmt(stakeDelta) },
    { type: 'mrkdwn', text: '*Movers*\n' + movers.length },
    { type: 'mrkdwn', text: '*Stuck/worse*\n' + stuck.length }
  ]},
  { type: 'divider' }
];

if (movers.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:white_check_mark: Top movers (clearing the deck)*' } });
  for (const a of movers.slice(0, 8)) blocks.push({ type: 'section', text: { type: 'mrkdwn', text: movLine(a) } });
  blocks.push({ type: 'divider' });
}
if (stuck.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:warning: Going the wrong way*' } });
  for (const a of stuck.slice(0, 8)) blocks.push({ type: 'section', text: { type: 'mrkdwn', text: movLine(a) } });
  blocks.push({ type: 'divider' });
}
if (nowCritical.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:rotating_light: Critical right now*\n' + nowCritical.slice(0, 12).map((a) => `${a.agent_name} (pd ${a.past_due_follow_ups || 0} / actionable ${a.total_stale || 0})`).join(', ') } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Midday call to action: managers ping their stuck agents now. After-action report at 7pm CST.' }] });

return [{ json: { text: 'Midday movement — ' + date + ': ' + movers.length + ' movers, ' + stuck.length + ' stuck', blocks } }];

// EOD — after-action: WTD CR + sales summary + per-agent email payloads
const payload = $node['Fetch Dataset & Parse'].json;
const agents = payload.agents || [];
const date = payload.scrape_date;
const agentEmails = payload.agentEmails || {};
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://YOUR_SUPABASE_REF.supabase.co/rest/v1';

// Determine WTD window (Mon..date inclusive, in agent CST)
const [yy, mm, dd] = date.split('-').map(Number);
const d = new Date(Date.UTC(yy, mm - 1, dd));
const dow = d.getUTCDay(); // 0=Sun .. 6=Sat
const daysSinceMon = (dow + 6) % 7; // 0 if Mon
const weekStart = new Date(d); weekStart.setUTCDate(d.getUTCDate() - daysSinceMon);
const weekStartIso = weekStart.toISOString().slice(0, 10);

// Pull WTD daily_scrape_data
let wtd = [];
try {
  wtd = await this.helpers.httpRequest({
    method: 'GET',
    url: base + '/daily_scrape_data?select=agent_name,scrape_date,ib_leads_delivered,ob_leads_delivered,ib_sales,ob_sales,custom_sales,ib_premium,ob_premium,custom_premium&scrape_date=gte.' + weekStartIso + '&scrape_date=lte.' + date,
    headers: { apikey },
    json: true
  }) || [];
} catch (e) { wtd = []; }
// Also pull WTD pool data for self-assigned and pool sales
let wtdPool = [];
try {
  wtdPool = await this.helpers.httpRequest({
    method: 'GET',
    url: base + '/leads_pool_daily_data?select=agent_name,scrape_date,sales_made,premium,self_assigned_leads&scrape_date=gte.' + weekStartIso + '&scrape_date=lte.' + date,
    headers: { apikey },
    json: true
  }) || [];
} catch (e) { wtdPool = []; }

const byAgent = {};
function get(name) { if (!byAgent[name]) byAgent[name] = { leads: 0, sales: 0, premium: 0, pool_sales: 0, pool_premium: 0, pool_self: 0 }; return byAgent[name]; }
for (const r of wtd) {
  const a = get(r.agent_name);
  a.leads   += (r.ib_leads_delivered || 0) + (r.ob_leads_delivered || 0);
  a.sales   += (r.ib_sales || 0) + (r.ob_sales || 0) + (r.custom_sales || 0);
  a.premium += (r.ib_premium || 0) + (r.ob_premium || 0) + (r.custom_premium || 0);
}
for (const r of wtdPool) {
  const a = get(r.agent_name);
  a.pool_sales   += (r.sales_made || 0);
  a.pool_premium += (r.premium || 0);
  a.pool_self    += (r.self_assigned_leads || 0);
}

const fmt = (n) => '$' + Math.round(n).toLocaleString();
const pct = (n, d) => (d > 0 ? ((n / d) * 100).toFixed(1) + '%' : 'N/A');

// Org totals
const orgLeads   = Object.values(byAgent).reduce((s, a) => s + a.leads + a.pool_self, 0);
const orgSales   = Object.values(byAgent).reduce((s, a) => s + a.sales + a.pool_sales, 0);
const orgPremium = Object.values(byAgent).reduce((s, a) => s + a.premium + a.pool_premium, 0);

// Agent rollup with end-of-day pipeline state.
// total_stale column = Actionable Leads (Past Due + Untouched).
// revenue_at_risk column = Premium @ Stake (Actionable × avg premium).
const rollup = agents.map((p) => {
  const w = byAgent[p.agent_name] || { leads: 0, sales: 0, premium: 0, pool_sales: 0, pool_premium: 0, pool_self: 0 };
  const totalLeads = w.leads + w.pool_self;
  const totalSales = w.sales + w.pool_sales;
  const overall    = totalLeads > 0 ? (totalSales / totalLeads) * 100 : 0;
  return {
    name: p.agent_name,
    email: agentEmails[p.agent_name] || null,
    pd_eod:         p.past_due_follow_ups || 0,
    untouched_eod:  p.new_leads || 0,
    actionable_eod: p.total_stale || 0,
    fu_eod:         p.todays_follow_ups || 0,
    queue_eod:      p.call_queue_count || 0,
    stake_eod:      p.revenue_at_risk || 0,
    wtd_leads: totalLeads,
    wtd_sales: totalSales,
    wtd_premium: w.premium + w.pool_premium,
    wtd_cr_pct: overall
  };
});
const sortedByPremium = [...rollup].sort((a, b) => b.wtd_premium - a.wtd_premium);
const topProducers = sortedByPremium.slice(0, 5);
const pipeOffenders = [...rollup].sort((a, b) => b.pd_eod - a.pd_eod || b.actionable_eod - a.actionable_eod).filter((a) => a.pd_eod > 3 || a.actionable_eod > 40).slice(0, 8);

const slackBlocks = [
  { type: 'header', text: { type: 'plain_text', text: ':checkered_flag: EOD After-Action — ' + date, emoji: true } },
  { type: 'section', text: { type: 'mrkdwn', text: '*WTD window:* ' + weekStartIso + ' → ' + date + '   ·   ' + agents.length + ' agents' } },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: '*WTD Sales*\n' + orgSales },
    { type: 'mrkdwn', text: '*WTD Premium*\n' + fmt(orgPremium) },
    { type: 'mrkdwn', text: '*WTD Overall CR*\n' + pct(orgSales, orgLeads) },
    { type: 'mrkdwn', text: '*WTD Leads*\n' + orgLeads }
  ]},
  { type: 'divider' }
];
slackBlocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:trophy: Top producers (WTD premium)*' } });
for (const a of topProducers) slackBlocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*${a.name}* — ${a.wtd_sales} sales · ${fmt(a.wtd_premium)} · ${a.wtd_cr_pct.toFixed(1)}% CR` } });
if (pipeOffenders.length > 0) {
  slackBlocks.push({ type: 'divider' });
  slackBlocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:rotating_light: Pipeline must clear by tomorrow morning*' } });
  for (const a of pipeOffenders) slackBlocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*${a.name}* — ${a.pd_eod} past due · ${a.actionable_eod} actionable · ${fmt(a.stake_eod)} premium @ stake` } });
}
slackBlocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Per-agent EOD email sent to anyone with an address on file. Set agents.email in Supabase to opt in.' }] });

// Per-agent email payloads (only for agents with email set)
const emails = rollup.filter((a) => a.email).map((a) => ({
  to: a.email,
  subject: `[DSB] EOD pipeline + WTD recap — ${date}`,
  html: [
    `<h2>End-of-day recap, ${a.name}</h2>`,
    `<p>Window: <strong>${weekStartIso} → ${date}</strong></p>`,
    `<h3>Week to date</h3>`,
    `<ul>`,
    `<li>Sales: <strong>${a.wtd_sales}</strong></li>`,
    `<li>Premium: <strong>${fmt(a.wtd_premium)}</strong></li>`,
    `<li>Leads (incl. pool self-assigned): <strong>${a.wtd_leads}</strong></li>`,
    `<li>Overall close rate: <strong>${a.wtd_cr_pct.toFixed(1)}%</strong></li>`,
    `</ul>`,
    `<h3>Pipeline at end of day</h3>`,
    `<ul>`,
    `<li>Past-due follow-ups: <strong>${a.pd_eod}</strong></li>`,
    `<li>Untouched leads: <strong>${a.untouched_eod}</strong></li>`,
    `<li><strong>Actionable backlog (past due + untouched): ${a.actionable_eod}</strong></li>`,
    `<li>Today's follow-ups (not yet worked): <strong>${a.fu_eod}</strong></li>`,
    `<li>Call queue (cadence is working it): <strong>${a.queue_eod}</strong></li>`,
    `<li>Premium @ stake on actionable backlog: <strong>${fmt(a.stake_eod)}</strong></li>`,
    `</ul>`,
    `<p>Critical = more than 3 past due OR more than 40 actionable. Clear past dues before any new activity tomorrow morning.</p>`,
    `<hr><p style="color:#888;font-size:11px">Automated DSB pipeline EOD report. Reply to your manager with questions.</p>`
  ].join('\n')
}));

return [{ json: {
  slack: { text: 'EOD after-action — ' + date, blocks: slackBlocks },
  emails,
  emailCount: emails.length,
  date,
  weekStartIso
}}];
